import authService from '../api/auth';

// 从localStorage获取用户信息
const userStr = localStorage.getItem('user');
let initialUser = null;

try {
  initialUser = userStr ? JSON.parse(userStr) : null;
  console.log('从localStorage获取的初始用户状态:', initialUser ? {
    username: initialUser.username,
    hasToken: !!initialUser.token || !!initialUser.accessToken,
    roles: initialUser.roles
  } : '无用户');
} catch (e) {
  console.error('解析localStorage中的用户信息失败:', e);
}

// 初始状态
const initialState = initialUser
  ? { status: { loggedIn: true }, user: initialUser }
  : { status: { loggedIn: false }, user: null };

export const auth = {
  namespaced: true,
  state: initialState,
  actions: {
    // 登录
    async login({ commit }, user) {
      try {
        console.log('auth模块: 开始登录流程，用户名:', user.username);

        // 调用登录服务
        const response = await authService.login(user.username, user.password);
        console.log('auth模块: 登录响应已接收');

        // 确保响应中包含必要的字段
        if (!response || (!response.token && !response.accessToken)) {
          console.error('auth模块: 登录响应中缺少token:', response);
          throw new Error('登录响应格式错误');
        }

        // 登录成功，提交mutation
        commit('loginSuccess', response);
        console.log('auth模块: 登录成功完成');

        return response;
      } catch (error) {
        console.error('auth模块: 登录失败:', error);
        commit('loginFailure');
        return Promise.reject(error);
      }
    },

    // 登出
    logout({ commit }) {
      authService.logout();
      commit('logout');
    },

    // 注册
    async register({ commit }, user) {
      try {
        const response = await authService.register(user.username, user.email, user.password);
        commit('registerSuccess');
        return Promise.resolve(response);
      } catch (error) {
        commit('registerFailure');
        return Promise.reject(error);
      }
    },

    // 刷新令牌
    async refreshToken({ commit }, accessToken) {
      commit('refreshToken', accessToken);
    },

    // 更新用户资料
    async updateProfile({ commit }, userData) {
      commit('updateUserProfile', userData);
    }
  },

  mutations: {
    // 登录成功
    loginSuccess(state, user) {
      state.status.loggedIn = true;
      state.user = user;
      console.log('auth模块: 登录状态已更新，已登录:', true);
    },

    // 登录失败
    loginFailure(state) {
      state.status.loggedIn = false;
      state.user = null;
      console.log('auth模块: 登录状态已更新，已登录:', false);
    },

    // 登出
    logout(state) {
      state.status.loggedIn = false;
      state.user = null;
      console.log('auth模块: 已登出');
    },

    // 注册成功
    registerSuccess(state) {
      state.status.loggedIn = false;
    },

    // 注册失败
    registerFailure(state) {
      state.status.loggedIn = false;
    },

    // 刷新令牌
    refreshToken(state, accessToken) {
      state.status.loggedIn = true;
      state.user = { ...state.user, accessToken };
    },

    // 更新用户资料
    updateUserProfile(state, userData) {
      if (state.user) {
        // 更新状态中的用户信息
        state.user = {
          ...state.user,
          ...userData
        };

        // 同时更新localStorage中的用户信息
        localStorage.setItem('user', JSON.stringify(state.user));
      }
    }
  },

  getters: {
    // 获取登录状态
    isLoggedIn: state => {
      const loginStatus = state.status.loggedIn;
      console.log('auth模块: 获取登录状态:', loginStatus);
      return loginStatus;
    },

    // 获取当前登录用户
    currentUser: state => {
      const user = state.user;
      console.log('auth模块: 获取当前用户:', user ? user.username : '无用户');
      return user;
    },

    // 获取用户名
    username: state => {
      if (!state.user) return ''; 
      return state.user.username || state.user.name || '';
    },

    // 获取用户角色
    userRoles: state => {
      if (!state.user || !state.user.roles) return [];
      return state.user.roles; 
    }
  }
};
